def find_max_min(numbers):
   max_val = float('-inf')
   min_val = float('inf')
   for num in numbers:
      if num > max_val:
         max_val = num
      if num < min_val:
         min_val = num
   return {'max': max_val, 'min': min_val, 'sum': sum(numbers), 'length': len(numbers)}

