def find_all_anagrams_in_list(wordlist, target_word):
   anagrams = {}
   for word in wordlist:
      sorted_word = sorted(word.lower())
      sorted_target_word = sorted(target_word.lower())
      if sorted_word == sorted_target_word:
         anagrams[word] = []
      for i in range(len(wordlist)):
         if i != wordlist.index(word):
            if sorted(wordlist[i].lower()) == sorted_target_word:
               anagrams[word].append(wordlist[i])
   return anagrams

