import math

def calculate_stats(data):
    stats = {'mean': 0, 'median': 0, 'std_dev': 0, 'max_value': float('-inf'), 'min_value': float('inf')}
    for value in data:
        stats['mean'] += value
        stats['median'] += value
        stats['std_dev'] += (value - stats['mean'] / len(data)) ** 2
        if value > stats['max_value']:
            stats['max_value'] = value
        if value < stats['min_value']:
            stats['min_value'] = value
    stats['mean'] /= len(data)
    stats['std_dev'] = math.sqrt(stats['std_dev'] / len(data))
    return stats

