import json

class DataStore:
    def __init__(self, file_name):
        self.data = {}
        self.file_name = file_name

    # Method to retrieve data from the store
    def retrieve_data(self):
        try:
            with open(self.file_name, 'r') as file:
                return self.data = json.load(file)
        except FileNotFoundError:
            return self.data

    # Method to save the data to a file
    def save_data(self):
        with open(self.file_name, 'w') as file:
            json.dump(self.data, file, indent=4)

    # Method to process the retrieved data
    def process_data(self, data):
        return {key.upper(): value for key, value in data.items()}

    # Method to update the data
    def update_data(self, data):
        return {key: value for key, value in data.items()}

    # Method to insert new data into the store
    def insert_new_data(self, key, value):
        self.data[key] = value

    # Method to delete an existing entry from the store
    def delete_entry(self, key):
        if key in self.data:
            del self.data[key]

