from typing import List, Dict

class Taxes:
    def __init__(self, rate: float):
        self.rate = rate

class Discount:
    def __init__(self, amount: float, customer_id: int):
        self.amount = amount
        self.customer_id = customer_id

class Order:
    def __init__(self, prices: List[float], shipping_cost: float, taxes: Taxes, discounts: List[Discount]):
        self.prices = prices
        self.shipping_cost = shipping_cost
        self.taxes = taxes
        self.discounts = discounts

    def calculate_subtotal(self) -> float:
        return sum(self.prices)

    def calculate_tax(self) -> float:
        return self.calculate_subtotal() * self.taxes.rate

    def calculate_discounts(self) -> float:
        return sum(d.amount for d in self.discounts)

    def calculate_final_total(self) -> float:
        return self.calculate_subtotal() - self.calculate_discounts() + self.calculate_tax() + self.shipping_cost

    def calculate_total(self) -> dict:
