def calculate_invoices(data: list, tax_rate: float, discount_rate: float) -> dict:
    total_cost = 0
    invoice_list = {}
    for invoice in data:
        cost = invoice['cost']
        tax = cost * tax_rate
        discount = cost * discount_rate
        invoice_list[invoice['id']] = {'cost': cost, 'tax': tax, 'discount': discount, 'total_cost': cost + tax - discount}
        total_cost += cost + tax - discount
    return {'total_cost': round(total_cost, 2), 'invoices': invoice_list}

def calculate_total_cost(invoice_data: list) -> float:
    return sum(invoice['cost'] for invoice in invoice_data)


def calculate_invoices_with_tax(data: list, tax_rate: float) -> dict:
    invoices = {}
    for invoice in data:
        invoices[invoice['id']] = {'cost': invoice['cost'], 'tax': invoice['cost'] * tax_rate, 'discount': 0, 'total_cost': invoice['cost']}
    return {'total_cost': sum(invoice['cost'] for invoice in data), 'invoices': invoices}


def main(data: list, tax_rate: float) -> dict:
