    pay -= employee_data['benefits_deduction']
  if employee_data['has_tax_withholding']:
    pay -= employee_data['tax_withholding']
  return pay
  # Example usage
  employee = {'type': 'hourly', 'hours_worked': 40, 'hourly_rate': 20.0, 'has_benefits': True, 'benefits_deduction': 10.0, 'has_tax_withholding': False, 'tax_withholding': 0.0}
  print(calculate_employee_pay(employee))

from dataclasses import dataclass
from enum import Enum
from typing import Dict

@dataclass
class Employee:
    type: str
    hours_worked: float
    hourly_rate: float
    has_benefits: bool
    benefits_deduction: float
    has_tax_withholding: bool
    tax_withholding: float

def calculate_pay(employee: Employee) -> float:
    if employee.type == 'hourly':
        return employee.hours_worked * employee.hourly_rate
    elif employee.type == 'salary':
        return employee.salary
    else:
        return 0

def calculate_benefits_deduction(employee: Employee) -> float:
    if employee.has_benefits:
        return employee.benefits_deduction
    else:
        return 0

def calculate_tax_withholding(employee: Employee) -> float:
    if employee.has_tax_withholding:
        return employee.tax_withholding
    else:
        return 0

def calculate_employee_pay(employee: Employee) -> float:
    pay = calculate_pay(employee)
    benefits_deduction = calculate_benefits_deduction(employee)
    tax_withholding = calculate_tax_withholding(employee)
    return pay - benefits_deduction - tax_withholding
  # Example usage
  employee = Employee(type='hourly', hours_worked=40, hourly_rate=20.0, has_benefits=True, benefits_deduction=10.0, has_tax_withholding=False, tax_withholding=0.0)
  print(calculate_employee_pay(employee))

